// =============================================
// 辅助函数
// =============================================

/**
 * 根据 slug 查找分类
 */
export function getCategoryBySlug(slug: string): StaticCategory | null {
  let cat = staticL1Categories.find(c => c.slug === slug);
  if (cat) return cat;
  cat = staticL2Categories.find(c => c.slug === slug);
  if (cat) return cat;
  cat = staticL3Categories.find(c => c.slug === slug);
  if (cat) return cat;
  return null;
}

/**
 * 根据 L1 slug 获取 L2 子分类
 */
export function getL2ByL1Slug(l1Slug: string): StaticCategory[] {
  return staticL2Categories.filter(c => c.parentSlug === l1Slug);
}

/**
 * 根据 L2 slug 获取 L3 子分类
 */
export function getL3ByL2Slug(l2Slug: string): StaticCategory[] {
  return staticL3Categories.filter(c => c.parentSlug === l2Slug);
}

/**
 * 根据 slug 获取父分类
 */
export function getParentCategory(slug: string): StaticCategory | null {
  const cat = getCategoryBySlug(slug);
  if (!cat || !cat.parentId) return null;
  
  if (cat.level === 3) {
    return staticL2Categories.find(c => c.id === cat.parentId) || null;
  }
  if (cat.level === 2) {
    return staticL1Categories.find(c => c.id === cat.parentId) || null;
  }
  return null;
}

/**
 * 获取所有分类（用于首页）
 */
export function getAllCategories(): StaticCategory[] {
  return staticL1Categories;
}
